import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

export default function Register() {
  const { register } = useAuth();
  const [form, setForm] = useState({ name:'', email:'', password:'', role:'member' });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (form.password.length < 6) return toast.error('Password must be 6+ characters');
    setLoading(true);
    try {
      await register(form);
      toast.success('Account created!');
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{minHeight:'100vh',display:'flex',alignItems:'center',justifyContent:'center',background:'linear-gradient(135deg,#0f172a,#065f46)',padding:'30px'}}>

      <div style={{width:'100%',maxWidth:'500px'}}>

        {/* LOGO */}
        <div style={{textAlign:'center',marginBottom:'30px'}}>
          <h1 style={{fontSize:'46px',fontWeight:'800',color:'#4ade80'}}>⚡ TeamTask</h1>
          <p style={{color:'#bbf7d0'}}>Create your account</p>
        </div>

        {/* CARD */}
        <div style={{background:'rgba(255,255,255,0.08)',padding:'35px',borderRadius:'18px',backdropFilter:'blur(12px)',border:'1px solid rgba(255,255,255,0.15)'}}>

          <form onSubmit={handleSubmit}>

            <div style={{marginBottom:'15px'}}>
              <label style={{fontSize:'14px',color:'#bbf7d0'}}>Full Name</label>
              <input
                placeholder="John Doe"
                value={form.name}
                onChange={e=>setForm({...form,name:e.target.value})}
                required
                style={{width:'100%',padding:'13px',marginTop:'6px',borderRadius:'8px',border:'1px solid rgba(255,255,255,0.2)',background:'rgba(255,255,255,0.1)',color:'#fff'}}
              />
            </div>

            <div style={{marginBottom:'15px'}}>
              <label style={{fontSize:'14px',color:'#bbf7d0'}}>Email</label>
              <input
                type="email"
                placeholder="you@example.com"
                value={form.email}
                onChange={e=>setForm({...form,email:e.target.value})}
                required
                style={{width:'100%',padding:'13px',marginTop:'6px',borderRadius:'8px',border:'1px solid rgba(255,255,255,0.2)',background:'rgba(255,255,255,0.1)',color:'#fff'}}
              />
            </div>

            <div style={{marginBottom:'15px'}}>
              <label style={{fontSize:'14px',color:'#bbf7d0'}}>Password</label>
              <input
                type="password"
                placeholder="Min 6 characters"
                value={form.password}
                onChange={e=>setForm({...form,password:e.target.value})}
                required
                style={{width:'100%',padding:'13px',marginTop:'6px',borderRadius:'8px',border:'1px solid rgba(255,255,255,0.2)',background:'rgba(255,255,255,0.1)',color:'#fff'}}
              />
            </div>

            <div style={{marginBottom:'20px'}}>
              <label style={{fontSize:'14px',color:'#bbf7d0'}}>Role</label>
              <select
                value={form.role}
                onChange={e=>setForm({...form,role:e.target.value})}
                style={{width:'100%',padding:'13px',marginTop:'6px',borderRadius:'8px',border:'1px solid rgba(255,255,255,0.2)',background:'rgba(255,255,255,0.1)',color:'#fff'}}
              >
                <option value="member">👤 Member</option>
                <option value="admin">🔑 Admin</option>
              </select>
            </div>

            <button
              type="submit"
              disabled={loading}
              style={{width:'100%',padding:'13px',borderRadius:'8px',border:'none',background:'linear-gradient(135deg,#22c55e,#4ade80)',color:'#022c22',fontWeight:'700',fontSize:'16px'}}
            >
              {loading ? 'Creating...' : 'Create Account →'}
            </button>

          </form>

          <p style={{textAlign:'center',marginTop:'18px',fontSize:'14px',color:'#bbf7d0'}}>
            Already have an account? <Link to="/login" style={{color:'#4ade80'}}>Sign In</Link>
          </p>

        </div>

      </div>
    </div>
  );
}
